create extension if not exists pgcrypto;
create table merchant_settings (id uuid primary key default gen_random_uuid(), whatsapp_number varchar not null, updated_at timestamptz not null default now());
create table sections (id uuid primary key default gen_random_uuid(), name varchar not null, slug varchar unique not null, icon_name varchar not null, display_order integer not null default 0, is_active boolean not null default true, created_at timestamptz not null default now(), deleted_at timestamptz);
create table products (id uuid primary key default gen_random_uuid(), name varchar not null, description text not null, section_id uuid not null references sections(id), primary_image_url varchar not null, base_price integer not null check(base_price>=0), is_active boolean not null default true, created_at timestamptz not null default now(), deleted_at timestamptz);
create table product_variants (id uuid primary key default gen_random_uuid(), product_id uuid not null references products(id) on delete cascade, label varchar not null, price_override integer check(price_override>=0), image_url varchar, is_in_stock boolean not null default true, display_order integer not null default 0, created_at timestamptz not null default now(), deleted_at timestamptz);
create index idx_products_section_active_deleted on products(section_id) where deleted_at is null and is_active=true; create index idx_products_created_sort on products(created_at desc); create index idx_variants_product on product_variants(product_id) where deleted_at is null; create index idx_sections_slug on sections(slug) where deleted_at is null and is_active=true;
alter table merchant_settings enable row level security; alter table sections enable row level security; alter table products enable row level security; alter table product_variants enable row level security;
create policy "settings readable" on merchant_settings for select using(true); create policy "sections readable" on sections for select using(deleted_at is null and is_active=true); create policy "products readable" on products for select using(deleted_at is null and is_active=true); create policy "variants readable" on product_variants for select using(deleted_at is null);
create policy "merchant settings writes" on merchant_settings for all to authenticated using(true) with check(true); create policy "merchant sections writes" on sections for all to authenticated using(true) with check(true); create policy "merchant products writes" on products for all to authenticated using(true) with check(true); create policy "merchant variants writes" on product_variants for all to authenticated using(true) with check(true);
insert into storage.buckets (id,name,public) values ('store-assets','store-assets',true) on conflict do nothing; create policy "public asset read" on storage.objects for select using(bucket_id='store-assets'); create policy "merchant asset write" on storage.objects for all to authenticated using(bucket_id='store-assets') with check(bucket_id='store-assets');
